#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
LL p,a,b,m,Ans=-1;
unordered_map<int,int> mp;
LL read(){
    LL su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
LL QP(LL x,LL y,LL mod){
    LL as=1;
    while(y){
        if(y&1)as=as*x%mod;
        x=x*x%mod,y>>=1;
    }return as;
}
int main(){
    p=read(),a=read(),b=read();
    m=sqrt(p)+2;
    LL tmp=b;
    for(int j=1;j<=m;j++){
        tmp=tmp*a%p;
        mp[tmp]=max(mp[tmp],j);
    }
    LL fan=QP(a,m,p);tmp=1;
    for(int i=1;i<=m&&Ans<0;i++){
        tmp=tmp*fan%p;
        if(mp[tmp]>0)Ans=i*m-mp[tmp];
    }
    if(Ans==-1)cout<<"no solution\n";
    else cout<<Ans<<"\n";
    return 0;
}
/*

求解满足 a^x = b ( mod p ) 的最小非负整数 x！

*/
